# Memory operations are first-class actions, not auxiliary controllers.
# The same LLM that picks task tools also picks memory tools.

MEMORY_OPS = {"ADD", "UPDATE", "DELETE", "RETRIEVE", "SUMMARY", "FILTER"}

class AgenticMemory:
    def __init__(self, ltm, stm):
        self.ltm = ltm   # long-term store (e.g. vector index)
        self.stm = stm   # short-term working context

    def apply(self, op, args):
        if op == "ADD":      return self.ltm.add(args["item"], meta=args.get("meta"))
        if op == "UPDATE":   return self.ltm.update(args["id"], args["patch"])
        if op == "DELETE":   return self.ltm.delete(args["id"])
        if op == "RETRIEVE": return self.stm.inject(self.ltm.search(args["query"], k=args.get("k", 5)))
        if op == "SUMMARY":  return self.stm.compress_span(args["span"])
        if op == "FILTER":   return self.stm.narrow(args["criteria"])
        raise ValueError(op)

function step(agent, mem, observation):
    action = agent.choose_action(observation, tools=TASK_TOOLS | MEMORY_OPS)
    if action.name in MEMORY_OPS:
        result = mem.apply(action.name, action.args)
    else:
        result = tool_dispatch(action)
    return result

# Step-wise reward shaper (e.g. step-wise GRPO) credits both task and
# memory actions against eventual task reward, so the two policies co-adapt.

# Prompted (not trained) variant of Agentic Memory: the six memory ops
# are declared as tools so Claude can choose them inside the agent loop.
# RL credit assignment lives outside this snippet — this is the action
# surface only.

MEMORY_TOOLS = [
    {
        "name": "memory_add",
        "description": "Write a new item into long-term memory.",
        "input_schema": {
            "type": "object",
            "properties": {
                "content": {"type": "string"},
                "tags":    {"type": "array", "items": {"type": "string"}},
            },
            "required": ["content"],
        },
    },
    {
        "name": "memory_update",
        "description": "Patch an existing long-term item.",
        "input_schema": {
            "type": "object",
            "properties": {
                "id":    {"type": "string"},
                "patch": {"type": "string"},
            },
            "required": ["id", "patch"],
        },
    },
    {
        "name": "memory_delete",
        "description": "Remove a long-term item by id.",
        "input_schema": {
            "type": "object",
            "properties": {"id": {"type": "string"}},
            "required": ["id"],
        },
    },
    {
        "name": "memory_retrieve",
        "description": "Semantic search; results enter short-term context.",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"},
                "k":     {"type": "integer"},
            },
            "required": ["query"],
        },
    },
    {
        "name": "memory_summary",
        "description": "Compress a span of short-term memory in place.",
        "input_schema": {
            "type": "object",
            "properties": {"span": {"type": "string"}},
            "required": ["span"],
        },
    },
    {
        "name": "memory_filter",
        "description": "Narrow short-term memory by a criterion.",
        "input_schema": {
            "type": "object",
            "properties": {"criteria": {"type": "string"}},
            "required": ["criteria"],
        },
    },
]

# The agent loop hands these six tools to the model alongside the task
# tools. When the model emits a `memory_*` tool call the loop dispatches
# it to a memory backend; otherwise it dispatches to the task tool.
# Every memory mutation is attributable to a single LLM action in the
# trace, which is the inspectability claim of Agentic Memory.

# Memory operations are first-class actions, not auxiliary controllers.
MEMORY_OPS = {"ADD", "UPDATE", "DELETE", "RETRIEVE", "SUMMARY", "FILTER"}

class AgenticMemory:
    def __init__(self, ltm, stm):
        self.ltm = ltm          # long-term store (vector index, scope="user")
        self.stm = stm          # short-term working context, scope="session"

    def apply(self, op, args):
        if op == "ADD":
            return self.ltm.write(args["content"], meta=args.get("meta"),
                                  scope="user", ttl=args.get("ttl"))
        if op == "UPDATE":   return self.ltm.update(args["id"], args["patch"])
        if op == "DELETE":   return self.ltm.delete(args["id"])
        if op == "RETRIEVE":
            hits = self.ltm.recall(args["query"], k=args.get("k", 5))
            return self.stm.inject(hits)
        if op == "SUMMARY":  return self.stm.compress_span(args["span"])
        if op == "FILTER":   return self.stm.narrow(args["criteria"])
        raise ValueError(op)

def step(agent, mem, observation):
    action = agent.choose_action(observation, tools=TASK_TOOLS | MEMORY_OPS)
    if action.name in MEMORY_OPS:
        return mem.apply(action.name, action.args)
    return tool_dispatch(action)

# Training: step-wise GRPO credits each memory action against eventual task
# reward, so the agent learns when remembering matters and when to forget.
for episode in training_data:
    trajectory = run_episode(episode)
    reward     = task_reward(trajectory)
    grpo_update(policy, trajectory, reward, per_step=True)

# Why this works: memory policy and task policy share one learned objective,
# so the agent learns to remember what will matter and forget what won't —
# decisions hand-tuned heuristics cannot make.
# Related: see `semantic-memory`, `episodic-memory`, `memgpt-paging`.

from langmem import create_memory_store_manager
from langgraph.store.memory import InMemoryStore

store = InMemoryStore(
    index={"dims": 1536, "embed": "openai:text-embedding-3-small"}
)

# Episodic channel: each call records a past interaction as an event;
# LangMem keeps timestamp + content so later retrieval can blend recency
# and similarity. Facts/skills are derived by separate channels.
episodic = create_memory_store_manager(
    "openai:gpt-4o-mini",
    namespace=("memories", "{user_id}", "episodes"),
    instructions=(
        "Record significant interactions as discrete events. Preserve "
        "who-said-what and outcome; do not collapse into facts."
    ),
    enable_inserts=True,
    store=store,
)

episodic.invoke(
    {
        "messages": [
            {"role": "user",      "content": "The auth CVE patch broke the SSO test."},
            {"role": "assistant", "content": "Reverted; opened a workaround ticket with TODO."},
        ]
    },
    config={"configurable": {"user_id": "alice"}},
)

# Recall returns past episodes (not extracted facts) for few-shot use.
episodes = store.search(
    ("memories", "alice", "episodes"),
    query="what happened with the auth workaround?",
    limit=5,
)
for ep in episodes:
    print(ep.value)

def maybe_summarise(thread):
    block = thread.unsummarised_messages()
    if tokens(block) < SUMMARY_THRESHOLD:
        return                                 # not enough material yet

    summary = llm.summarise(
        block,
        instructions="Preserve gist: decisions, facts, open questions."
    )
    summary_store.append({
        "thread": thread.id,
        "range": (block[0].id, block[-1].id),
        "text": summary,
        "ts": now(),
    })
    archive.move(block)                        # originals go cold, not deleted

def load_for_turn(thread):
    # Reads always consult the summary tier first.
    summaries = summary_store.recent(thread.id, k=5)
    recent    = thread.tail(n=10)
    return [system_prompt(history_summary=summaries), *recent]

function ingest(observation):
    # 1. Extract typed entities and relations.
    triples = llm.extract(
        observation,
        schema="(:Entity {id, type, name}) -[:REL {type}]-> (:Entity ...)"
    )
    # 2. Upsert into the graph store.
    for (h, r, t) in triples:
        graph.merge_node(h); graph.merge_node(t)
        graph.merge_edge(h, r, t)
        vector_index.add(h.id, embed(h.name))   # entry-point embedding

function query(question):
    # Vector finds plausible entry points; graph traverses from there.
    seeds = vector_index.search(embed(question), k=3)
    subgraph = graph.expand(seeds, depth=2)
    return llm.answer(question, evidence=subgraph)

# Compose memgpt-paging with five-tier-memory-cascade: the archival
# side is not one flat bucket but a tiered cascade. The model's paging
# tools target a tier explicitly, so 'search archival' becomes 'search
# the right time horizon'.

# Tiers in order of recency.
TIERS = ["hour", "day", "week", "month", "lifetime"]

class TieredArchival:
    def __init__(self):
        self.stores = {t: VectorStore(scope=f"archive:{t}") for t in TIERS}

    def insert(self, text):
        # New entries land in the hottest tier.
        self.stores["hour"].upsert(id=uuid(), text=text, ts=now())

    def search(self, query, tier):
        return self.stores[tier].search(embed(query), k=5)

    def cascade(self):
        # Promote stale entries down the cascade; older tiers hold
        # summaries rather than verbatim entries.
        for src, dst in zip(TIERS, TIERS[1:]):
            for item in self.stores[src].older_than(TIER_AGE[src]):
                summary = llm.summarise(item.text)
                self.stores[dst].upsert(id=item.id, text=summary,
                                          ts=item.ts)
                self.stores[src].delete(item.id)

archival = TieredArchival()
every("1h", archival.cascade)

tools = {
    "search_hour":     lambda q: archival.search(q, "hour"),
    "search_day":      lambda q: archival.search(q, "day"),
    "search_week":     lambda q: archival.search(q, "week"),
    "search_month":    lambda q: archival.search(q, "month"),
    "search_lifetime": lambda q: archival.search(q, "lifetime"),
    "write_archival":  lambda text: archival.insert(text),
}

def run_turn(user_msg, main_ctx):
    while True:
        reply = llm.generate(messages=main_ctx + [user(user_msg)], tools=tools)
        if not reply.tool_calls:
            return reply.content
        for call in reply.tool_calls:
            # The model decides WHICH tier to page from, not just whether.
            main_ctx.append(tool_result(call.id,
                                          tools[call.name](**call.args)))
        main_ctx = evict_oldest_if_over_budget(main_ctx)

# Why this works: MemGPT's flat 'archival' bucket grows monotonically
# and loses signal as it ages; composing with the five-tier cascade
# means the model addresses the right time horizon directly, pays only
# for the granularity it asks for, and older tiers carry summaries
# instead of raw text.
# Related: see `five-tier-memory-cascade`, `vector-memory`, `tool-use`.

# Each memory type goes to the store that matches its access pattern.
class MemoryLayer:
    def __init__(self):
        self.episodic   = RedisStore()              # sub-ms reads on recent
        self.semantic   = VectorDB("pinecone")     # similarity search
        self.procedural = WorkflowStore("postgres") # ACID + versioning

    def write(self, kind, key, value, scope=None, ttl=None):
        if kind == "episodic":
            self.episodic.write(key=key, value=value,
                                scope=scope or "user", ttl=ttl or "24h")
        elif kind == "semantic":
            self.semantic.upsert(id=key, embedding=embed(value["text"]),
                                 metadata=value["meta"])
        elif kind == "procedural":
            self.procedural.commit(workflow_id=key, definition=value,
                                   version=next_version(key))
        else:
            raise ValueError(kind)

    def recall(self, kind, query, k=5):
        if kind == "episodic":
            return self.episodic.recent_by(query["user_id"], n=k)
        if kind == "semantic":
            return self.semantic.search(embed(query["text"]), k=k)
        if kind == "procedural":
            return self.procedural.lookup(situation=query["situation"])
        raise ValueError(kind)

mem = MemoryLayer()
mem.write("episodic",   key=session_id,    value={"intent": ..., "summary": ...},
          scope="user", ttl="1h")
mem.write("semantic",   key=fact_id,       value={"text": ..., "meta": ...})
mem.write("procedural", key=workflow_id,   value=workflow_definition)

# Why this works: episodic needs sub-millisecond recency reads; semantic
# needs similarity search; procedural needs ACID + versioning. No single
# store wins all three. Routing per type buys latency, cost, AND correctness.
# Related: see `three-layers-agent-memory`, `episodic-memory`, `semantic-memory`.

# Compose storage-specialisation with three-layers-agent-memory: STM,
# LTM, and Feedback each delegate per memory TYPE to the matching
# storage technology, and promotion across layers is a write into the
# layer that owns the correct store.

class LayeredSpecialisedMemory:
    def __init__(self):
        # STM = recent context, fast in-memory.
        self.stm = {
            "episodic":   RedisStore(ttl="1h"),
            "semantic":   InMemoryVectorCache(),
            "procedural": InMemoryProcessQueue(),
        }
        # LTM = durable, persistent.
        self.ltm = {
            "episodic":   PostgresEpisodicLog(),
            "semantic":   VectorDB("weaviate"),
            "procedural": WorkflowStore("postgres"),
        }
        self.feedback = FeedbackBus()

    def stm_write(self, kind, key, value, scope="session"):
        self.stm[kind].write(key=key, value=value, scope=scope)

    def ltm_recall(self, kind, query, scope="user", k=5):
        return self.ltm[kind].recall(query, scope=scope, k=k)

    def promote(self, kind, key):
        # Promotion is per-type: episodic to log, semantic to vector DB,
        # procedural to workflow engine with versioning.
        item = self.stm[kind].read(key)
        if not item: return
        if kind == "procedural":
            self.ltm[kind].commit(workflow_id=key, definition=item,
                                    version=next_version(key))
        else:
            self.ltm[kind].write(key=key, value=item, scope="user")
        self.stm[kind].mark_promoted(key)

    def on_feedback(self, signal):
        # Feedback refines the right store: corrections patch semantic
        # facts; engagement drops shrink STM episodic windows; errors
        # demote procedural workflows.
        if signal.kind == "correction":
            self.ltm["semantic"].update(signal.target_id, signal.patch)
        if signal.kind == "engagement_drop":
            self.stm["episodic"].shrink_window()
        if signal.kind == "error":
            self.ltm["procedural"].demote(signal.target_id)

mem = LayeredSpecialisedMemory()
every(PROMOTION_INTERVAL, lambda: [mem.promote(k, key)
                                     for k, store in mem.stm.items()
                                     for key in store.unpromoted()])

# Why this works: storage specialisation alone gives you fast right
# stores; the three-layer model gives you promotion and feedback. Wired
# together, each layer keeps its discipline while each TYPE keeps the
# store that fits its access pattern.
# Related: see `three-layers-agent-memory`, `episodic-memory`, `vector-memory`.

# Episode = [user_turn, (assistant + tool_calls + tool_results)*, assistant_final]
# Reasoning trace is episode-scoped.

def build_context(history):
    out = []
    # 1. Find the start of the CURRENT episode = index of the last user msg.
    last_user = max(i for i, m in enumerate(history) if m.role == "user")

    for i, msg in enumerate(history):
        if msg.role == "assistant":
            if i >= last_user:
                # Inside current episode — preserve reasoning_content so the
                # model can chain its own thinking across tool round-trips.
                out.append(msg)              # includes reasoning_content
            else:
                # Past episode — strip reasoning, keep only user-visible text.
                out.append(msg.without_reasoning())
        else:
            out.append(msg)                  # user / tool messages unchanged
    return out

# At the next user turn the previous reasoning_content silently drops; the
# API would reject or ignore stale reasoning blocks across episodes anyway.

# Production episode store: reasoning_content is persisted under an
# episode key with a TTL that expires at the next user turn; a budget
# bounds how much trace we carry; audit keeps a debug-time copy.

class EpisodeReasoningStore:
    def __init__(self):
        self.store = KV()        # scoped per session
        self.audit = AuditLog()

    def write(self, session_id, episode_id, turn_idx, reasoning):
        budget = REASONING_TOKEN_BUDGET
        if tokens(reasoning) > budget:
            reasoning = summarise(reasoning, target=budget)
        self.store.write(
            key   = (session_id, episode_id, turn_idx),
            value = {"reasoning": reasoning, "ts": now()},
            scope = f"session:{session_id}",
            ttl   = EPISODE_TTL,                  # short — episode-bounded
        )
        self.audit.record(op="reasoning.write",
                           session=session_id, episode=episode_id)

    def read_for_current_episode(self, session_id, episode_id):
        return self.store.scan(
            prefix=(session_id, episode_id),
            scope=f"session:{session_id}",
        )

    def expire_old_episodes(self, session_id, current_episode):
        for k in self.store.keys(scope=f"session:{session_id}"):
            if k[1] != current_episode:
                self.store.delete(k)
                self.audit.record(op="reasoning.expire", key=k)

estore = EpisodeReasoningStore()

def on_user_turn(session_id, user_msg):
    new_episode = next_episode_id(session_id)
    estore.expire_old_episodes(session_id, current_episode=new_episode)
    return new_episode

def build_context(session_id, episode_id, history):
    out = []
    current_trace = estore.read_for_current_episode(session_id, episode_id)
    for msg in history:
        if msg.role == "assistant":
            r = current_trace.get((msg.turn_idx,))
            if r:
                out.append(msg.with_reasoning(r["reasoning"]))
            else:
                out.append(msg.without_reasoning())   # past episode
        else:
            out.append(msg)
    return out

# Why this works: TTL keyed to episode boundary makes the 'expire at
# next user turn' rule structural rather than aspirational; the budget
# stops one ruminating turn from blowing out context; the audit lets
# you reconstruct the model's chain of thought when debugging a bug
# that already evaporated from production memory.
# Related: see `extended-thinking`, `prompt-caching`, `short-term-memory`.

# Weights are persisted in a config so a reflection pass can adjust them.
weights = load_yaml("salience.yaml")  # alpha, beta, gamma, delta, epsilon

def salience(item, goal, ctx):
    return (
        weights["alpha"]   * novelty(item, ctx.recent_attended)
      + weights["beta"]    * goal_relevance(item, goal)
      + weights["gamma"]   * recency(item, now())
      + weights["delta"]   * prediction_error(item, ctx.last_prediction)
      - weights["epsilon"] * fatigue(item, ctx.attention_log)
        # fatigue penalises items attended N times in the recent window;
        # this is what breaks rumination loops on the same memory.
    )

def select_working_set(candidates, goal, ctx, k=7):
    scored = [(salience(c, goal, ctx), c) for c in candidates]
    scored.sort(reverse=True)
    chosen = [c for _, c in scored[:k]]
    for c in chosen:
        ctx.attention_log.record(c.id, now())   # feeds future fatigue term
    return chosen

# Compose salience-attention with multi-axis-promotion-scoring: both
# components draw from one axis registry. Salience scores items for
# THIS tick's attention; the promotion scorer evaluates whether the
# attended item should be written to long-term memory.

AXES = {
    "novelty":          novelty,
    "goal_relevance":   goal_relevance,
    "recency":          recency,
    "prediction_error": prediction_error,
    "affect_intensity": affect_intensity,
    "recurrence":       recurrence_in_window,
}

class UnifiedScorer:
    def __init__(self):
        self.salience_weights = {"novelty": 0.3, "goal_relevance": 0.4,
                                  "recency": 0.2, "prediction_error": 0.1}
        self.promotion_weights = {"recurrence": 0.35, "affect_intensity": 0.25,
                                   "goal_relevance": 0.25, "prediction_error": 0.15}

    def salience(self, item, ctx):
        return sum(w * AXES[name](item, ctx)
                    for name, w in self.salience_weights.items())

    def promotion(self, item, ctx):
        return sum(w * AXES[name](item, ctx)
                    for name, w in self.promotion_weights.items())

scorer = UnifiedScorer()

def tick(candidates, goal, ctx, short_term, long_term):
    # 1. Salience: pick top-k for THIS tick's attention.
    attended = sorted(candidates, key=lambda c: scorer.salience(c, ctx),
                       reverse=True)[:7]
    for item in attended:
        short_term.write(key=item.id, value=item,
                          scope="short_term", ttl_cycles=4)

        # 2. Promotion: does this attended item deserve LTM?
        p = scorer.promotion(item, ctx)
        if p >= PROMOTION_THRESHOLD:
            long_term.write(
                key   = (item.kind, item.id),
                value = distil(item),
                scope = "agent",
            )

# Why this works: salience answers 'attend now?' and promotion answers
# 'keep forever?' — they share an axis registry so the two questions
# stay coherent. Tuning one axis updates both, and the agent stops
# remembering things it never paid attention to.
# Related: see `multi-axis-promotion-scoring`, `episodic-summaries`, `five-tier-memory-cascade`.

class Scratchpad:
    def __init__(self): self._lines = []
    def read(self):    return "\n".join(self._lines)
    def write(self, line): self._lines.append(line)
    def clear(self):   self._lines = []

scratch = Scratchpad()

tools = [
    Tool("scratch_read",  lambda: scratch.read()),
    Tool("scratch_write", lambda line: scratch.write(line)),
]

function handle_turn(user_msg):
    messages = [
        system_prompt(
            "You have a scratchpad. Use scratch_write for intermediate "
            "notes that should NOT appear in your reply. Read it whenever "
            "you need to recall something you wrote earlier."
        ),
        {"role": "system", "content": f"Scratchpad:\n{scratch.read()}"},
        user(user_msg),
    ]
    reply = agent_loop(messages, tools)
    return reply.content    # scratchpad contents never leak into the reply

on_task_complete(lambda: scratch.clear())   # purge at completion

# Periodic miner over the agent's own corpus -> top-N vocabulary cache.
# Downstream scoring blends generic similarity with own-vocab overlap.

import json, math

def mine_vocabulary(corpus_window, top_n=30):
    # 1. Collect candidate tokens: frontmatter tags + content tokens.
    df_tag    = {}    # tag frequency across entries
    df_token  = {}    # content-token frequency
    N         = 0
    for entry in corpus_window:
        N += 1
        for tag in entry.tags:
            df_tag[tag] = df_tag.get(tag, 0) + 1
        for tok in tokenise(entry.content):
            if not is_stopword(tok):
                df_token[tok] = df_token.get(tok, 0) + 1

    # 2. Blend: tags weighted higher than raw content tokens.
    blended = {}
    for tag, n in df_tag.items():
        blended[tag] = (n / N) * 2.0
    for tok, n in df_token.items():
        blended[tok] = blended.get(tok, 0) + (n / N)

    # 3. Top-N as the cached vocabulary.
    top = sorted(blended.items(), key=lambda kv: kv[1], reverse=True)[:top_n]
    return {"refreshed_at": now(), "vocab": dict(top)}

def refresh(cache_path, corpus_window):
    vocab = mine_vocabulary(corpus_window)
    json.dump(vocab, open(cache_path, "w"))

def own_frame_score(thought, vocab):
    toks = set(tokenise(thought))
    return sum(w for tok, w in vocab["vocab"].items() if tok in toks)

def salience(thought, recent_ctx, vocab, alpha=0.5, beta=0.5):
    # Two-axis score: generic similarity + own-frame fit.
    return (
        alpha * cosine(embed(thought), embed(recent_ctx))
      + beta  * own_frame_score(thought, vocab)
    )

# Refresh cadence: weekly for stable agents; after each consolidation
# pass for more volatile ones. A reflection step can audit churn vs
# lock-in and adjust the cadence.

# Substrate is orthogonal: vector store, graph, or profile doc all work.
class SemanticStore:
    def assert_(self, entity, attribute, value, provenance, scope="user"):
        key = (entity, attribute)
        prior = self.store.read(key, scope=scope)
        if prior and prior["value"] != value:
            # Conflict: keep both, mark superseded; never silently overwrite.
            self.store.write(
                key   = key,
                value = {"value":      value,
                         "prov":       provenance,
                         "asserted_at": now(),
                         "supersedes": prior["id"]},
                scope = scope,
            )
        else:
            self.store.write(
                key   = key,
                value = {"value": value, "prov": provenance,
                         "asserted_at": now()},
                scope = scope,
            )

    def recall(self, entity, attribute=None, scope="user"):
        if attribute is None:
            return self.store.scan_prefix((entity,), scope=scope)
        return self.store.read((entity, attribute), scope=scope)

semantic = SemanticStore()

# Extraction path: episodes -> assertions, written with provenance.
def extract_and_assert(episode):
    for (entity, attribute, value) in llm.extract_assertions(episode):
        semantic.assert_(entity, attribute, value,
                         provenance={"episode_id": episode.id,
                                     "extractor": "llm"})

# Read path at decision time — keyed lookup, not similarity-over-quotes.
