# Why this works: facts live under stable (entity, attribute) keys with
# provenance, so 'user prefers dark mode' is retrievable as an assertion
# rather than as a similarity hit against the day they happened to say it.
# Conflict-as-supersession preserves the audit trail.
# Related: see `episodic-memory`, `vector-memory`, `knowledge-graph-memory`.

@dataclass
class ThreadState:
    messages:    list
    active_plan: dict | None
    screen:      str | None
    agent_step:  int
    updated_at:  float

store = KV()  # any TTL-aware KV: Redis, DynamoDB w/ TTL, etc.
TTL = 24 * 3600

def load(thread_id) -> ThreadState:
    raw = store.get(thread_id)
    if not raw or now() - raw["updated_at"] > TTL:
        return ThreadState(messages=[], active_plan=None,
                           screen=None, agent_step=0,
                           updated_at=now())   # expired -> reset
    return ThreadState(**raw)

def save(thread_id, st: ThreadState):
    st.updated_at = now()
    store.put(thread_id, asdict(st), ttl=TTL)

function handle_turn(thread_id, user_msg):
    st = load(thread_id)
    st.messages.append(user(user_msg))
    reply = llm.generate(messages=st.messages, state=st)
    st.messages.append(reply); st.agent_step += 1
    save(thread_id, st)
    return reply.content

# Titans-style: per-session neural memory updated by gradient steps at
# inference time. The module is ephemeral; its state is scope="session".

class NeuralMemoryModule:
    def __init__(self, dim):
        self.theta = init_params(dim)         # per-session weights
        self.opt   = SGD(lr=INFERENCE_LR)

    def write(self, input_repr, target_repr):
        # Gradient step AT INFERENCE TIME.
        loss = recon_loss(self.forward(input_repr), target_repr)
        grads = backward(loss, self.theta)
        self.opt.step(self.theta, grads)

    def read(self, query_repr):
        return self.forward(query_repr)       # parametric recall

class SessionAgent:
    def __init__(self, base_model):
        self.base = base_model                # frozen pre-trained weights
        self.mem  = NeuralMemoryModule(dim=base_model.hidden_dim)

    def on_session_start(self):
        self.mem = NeuralMemoryModule(dim=self.base.hidden_dim)   # fresh

    def step(self, user_input):
        x = embed(user_input)

        # Memorise the new input into the per-session module.
        self.mem.write(input_repr=x, target_repr=x)

        # Recall: the module's learned response augments the base model.
        recalled = self.mem.read(query_repr=x)
        return self.base.generate(input=x, augmented_with=recalled)

    def on_session_end(self):
        # Module is ephemeral by design; nothing persists.
        self.mem = None

# Why this works: pre-trained-only models cannot learn within a session;
# RAG retrieves but does not integrate. A parametric memory updated at
# inference time is faster than retraining and more integrated than
# retrieval — the model 'remembers' the session in its weights.
# Related: see `episodic-memory`, `agentic-memory`, `landmark-attention`.

# Production test-time memory: per-session module with bounded size,
# rate-limited gradient steps, scope-enforced lifecycle, and an audit
# of every write so a debugger can ask 'what did this module learn?'

MODULE_PARAM_BUDGET = 32 * 1024 * 1024     # 32MB cap per session
WRITE_RATE          = 10                   # gradient steps per minute

class NeuralMemoryModule:
    def __init__(self, dim, session_id, user_id):
        self.theta      = init_params(dim, max_bytes=MODULE_PARAM_BUDGET)
        self.opt        = SGD(lr=INFERENCE_LR)
        self.session_id = session_id
        self.user_id    = user_id
        self.write_log  = RollingWindow(WRITE_RATE, window="1m")
        self.audit      = AuditLog()

    def write(self, input_repr, target_repr):
        if self.write_log.full():
            metrics.inc("ttm.rate_limited")
            return                            # drop excess writes
        loss   = recon_loss(self.forward(input_repr), target_repr)
        grads  = backward(loss, self.theta)
        self.opt.step(self.theta, grads)
        self.write_log.record(now())
        self.audit.record(
            op="ttm.write", session=self.session_id, user=self.user_id,
            loss=float(loss),
        )

    def read(self, query_repr):
        return self.forward(query_repr)

class ScopedAgent:
    def __init__(self, base_model):
        self.base = base_model
        self.modules_by_session = {}          # scope enforcement

    def on_session_start(self, session_id, user_id):
        # New module per session — weights from prior sessions never
        # bleed into this one.
        self.modules_by_session[session_id] = NeuralMemoryModule(
            dim=self.base.hidden_dim,
            session_id=session_id, user_id=user_id,
        )

    def step(self, session_id, user_input):
        mem = self.modules_by_session.get(session_id)
        if mem is None:
            raise ScopeError(f"no module for session {session_id}")
        x = embed(user_input)
        mem.write(input_repr=x, target_repr=x)
        return self.base.generate(input=x,
                                    augmented_with=mem.read(query_repr=x))

    def on_session_end(self, session_id):
        mod = self.modules_by_session.pop(session_id, None)
        if mod:
            mod.audit.record(op="ttm.dispose", session=session_id)

# Why this works: the parameter budget keeps memory cost predictable;
# the write rate limit prevents a noisy session from monopolising the
# inference loop; scope enforcement makes cross-session weight leakage
# structurally impossible; the audit makes the otherwise-opaque updates
# legible to debugging.
# Related: see `episodic-memory`, `agentic-memory`, `landmark-attention`.

class ThreeLayerMemory:
    def __init__(self):
        self.stm = BoundedSessionContext(max_tokens=8000, scope="session")
        self.ltm = StructuredStore(scope="user", index="vector+graph")
        self.feedback = FeedbackBus()

    # --- STM: immediate session context ---
    def stm_write(self, msg):
        self.stm.append(msg, ts=now())
        if self.stm.over_budget():
            self.stm.compact_oldest()                # token management

    # --- Promotion rule: STM -> LTM ---
    def maybe_promote(self):
        for span in self.stm.unpromoted_spans():
            if is_durable_knowledge(span):           # named entity, decision, fact
                distilled = llm.distil(span)
                self.ltm.write(
                    key   = (distilled.entity, distilled.attribute),
                    value = distilled,
                    scope = "user",
                )
                self.stm.mark_promoted(span)

    # --- LTM: persistent, indexed ---
    def ltm_recall(self, query, k=5):
        return self.ltm.recall(query, k=k)

    # --- Feedback core: refines BOTH layers ---
    def on_feedback(self, signal):
        # Explicit: rating, correction. Implicit: engagement, error rate.
        if signal.kind == "correction":
            self.ltm.update(signal.target_id, signal.patch)
        if signal.kind == "engagement_drop":
            self.stm.shrink_recall_window()          # refine STM behaviour
        if signal.kind == "error":
            self.ltm.demote(signal.target_id)        # refine LTM trust
        self.feedback.log(signal)

memory = ThreeLayerMemory()
every(PROMOTION_INTERVAL, memory.maybe_promote)
feedback_bus.subscribe(memory.on_feedback)

# Why this works: treating the three as independent leaves STM amnesic, LTM
# stale, and feedback unused. As one architecture with explicit promotion
# and refinement boundaries, the layers reinforce each other.
# Related: see `short-term-memory`, `episodic-memory`, `memory-type-storage-specialization`.

# Production three-layer memory: each layer has a latency SLO, LTM has
# explicit conflict policy, the feedback bus has backpressure, and
# every promotion is audited.

SLO_MS  = {"stm": 5, "ltm": 60, "feedback": 200}

class ProductionThreeLayer:
    def __init__(self):
        self.stm   = BoundedSessionContext(max_tokens=8000, scope="session")
        self.ltm   = StructuredStore(scope="user", index="vector+graph")
        self.bus   = BackpressuredBus(max_queue=10_000)
        self.audit = AuditLog()

    def stm_write(self, session_id, msg):
        t0 = monotonic_ms()
        self.stm.write(scope=f"session:{session_id}", msg=msg, ts=now())
        observe_or_alert("stm", monotonic_ms() - t0)
        if self.stm.over_budget(session_id):
            self.stm.compact_oldest(session_id)

    def maybe_promote(self, session_id, user_id):
        for span in self.stm.unpromoted_spans(session_id):
            if not is_durable_knowledge(span):
                continue
            distilled = llm.distil(span)
            key   = (distilled.entity, distilled.attribute)
            existing = self.ltm.read(key=key, scope=f"user:{user_id}")
            if existing:
                # Supersede vs append: keep the newer fact if the
                # source is more recent, otherwise append as a note.
                if distilled.ts > existing["ts"]:
                    self.ltm.write(key=key, value=distilled,
                                     scope=f"user:{user_id}",
                                     mode="supersede")
                else:
                    self.ltm.write(key=key + ("note", uuid()),
                                     value=distilled,
                                     scope=f"user:{user_id}",
                                     mode="append")
            else:
                self.ltm.write(key=key, value=distilled,
                                 scope=f"user:{user_id}", mode="supersede")
            self.audit.record(op="promote", from_="stm", to="ltm",
                               session=session_id, user=user_id,
                               key=key)
            self.stm.mark_promoted(session_id, span)

    def on_feedback(self, signal):
        if not self.bus.try_enqueue(signal):
            metrics.inc("feedback.dropped")
            return
        for s in self.bus.drain(budget_ms=SLO_MS["feedback"]):
            self._apply_feedback(s)

    def _apply_feedback(self, s):
        if s.kind == "correction":
            self.ltm.update(s.target_id, s.patch)
        if s.kind == "engagement_drop":
            self.stm.shrink_recall_window()
        if s.kind == "error":
            self.ltm.demote(s.target_id)
        self.audit.record(op="feedback.apply", kind=s.kind,
                           target=s.target_id)

# Why this works: SLO budgets per layer keep one slow layer from
# blocking another; explicit supersede-vs-append makes the LTM write
# semantics testable; backpressure on feedback stops a burst from
# blowing the whole loop; audit on each promotion makes layer crossings
# debuggable.
# Related: see `short-term-memory`, `episodic-memory`, `memory-type-storage-specialization`.

# Compose three-layer memory with episodic-memory: LTM is not one bag
# but a partitioned store. Promotion classifies STM spans by kind
# (episodic event, semantic fact, procedural how-to) and routes them
# to the right sub-store; feedback updates the right partition.

class PartitionedThreeLayer:
    def __init__(self):
        self.stm = BoundedSessionContext(max_tokens=8000, scope="session")
        self.ltm = {
            "episodic":   EpisodicLog(scope="user"),
            "semantic":   VectorStore(scope="user"),
            "procedural": WorkflowStore(scope="user"),
        }
        self.bus = FeedbackBus()

    def classify_span(self, span):
        # Lightweight router: episodic = lived event with a timestamp,
        # semantic = fact about the world or user, procedural = how-to.
        if span.has_temporal_anchor and span.is_event:
            return "episodic"
        if span.is_assertion:
            return "semantic"
        if span.is_how_to:
            return "procedural"
        return None

    def maybe_promote(self, session_id, user_id):
        for span in self.stm.unpromoted_spans(session_id):
            kind = self.classify_span(span)
            if not kind:
                continue
            distilled = llm.distil(span, schema=SCHEMAS[kind])
            self.ltm[kind].write(
                key   = distilled.key,
                value = distilled,
                scope = f"user:{user_id}",
            )
            self.stm.mark_promoted(span)

    def ltm_recall(self, query, user_id, k=5):
        # Fan out across partitions; the caller chooses how to merge.
        return {
            kind: store.recall(query=query, scope=f"user:{user_id}", k=k)
            for kind, store in self.ltm.items()
        }

    def on_feedback(self, signal):
        if signal.kind == "correction" and signal.target_kind:
            self.ltm[signal.target_kind].update(signal.target_id,
                                                  signal.patch)

# Why this works: a single LTM bag flattens episodic, semantic, and
# procedural knowledge into one similarity surface. Composing with
# episodic-memory's partitioning means promotion writes to the store
# whose access pattern matches the knowledge kind, and recall can ask
# 'what episodes', 'what facts', or 'what procedures' separately.
# Related: see `episodic-memory`, `semantic-memory`, `procedural-memory`.
